class ElasticsearchLogHandler(Handler):
    def __init__(
        self,
        es_client: ElasticsearchClient,
        index_prefix: str = DEFAULT_LOG_INDEX_PREFIX,
        service: str = DEFAULT_APP_NAME,
        environment: str = os.getenv("APP_ENV", "development"),
    ):
        super().__init__()
        self.es_client = es_client
        self.index_prefix = index_prefix
        self.service = service
        self.environment = environment
        self.hostname = socket.gethostname()

    def emit(self, record: LogRecord) -> None:
        try:
            document = self._record_to_document(record)
            index_name = self.es_client.current_log_index(self.index_prefix)
            self.es_client.index_document(index_name=index_name, document=document, refresh=False)
        except Exception:
            self.handleError(record)

    def _record_to_document(self, record: LogRecord) -> Dict[str, Any]:
        exception_text = None
        if record.exc_info:
            exception_text = self.formatException(record.exc_info) if hasattr(self, "formatException") else logging.Formatter().formatException(record.exc_info)

        reserved = {
            "name", "msg", "args", "levelname", "levelno", "pathname", "filename", "module",
            "exc_info", "exc_text", "stack_info", "lineno", "funcName", "created", "msecs",
            "relativeCreated", "thread", "threadName", "processName", "process", "message",
            "asctime"
        }
        extra = {k: v for k, v in record.__dict__.items() if k not in reserved}

        return {
            "@timestamp": datetime.fromtimestamp(record.created, tz=timezone.utc).isoformat(),
            "message": record.getMessage(),
            "logger": record.name,
            "level": record.levelname,
            "service": self.service,
            "environment": self.environment,
            "host": self.hostname,
            "module": record.module,
            "function": record.funcName,
            "line": record.lineno,
            "process": record.process,
            "thread": record.threadName,
            "pathname": record.pathname,
            "exception": exception_text,
            "extra": extra,
        }


