def configure_application_logger(log_service: LogService, logger_name: str = DEFAULT_APP_NAME, level: int = logging.INFO) -> logging.Logger:
    logger = logging.getLogger(logger_name)
    logger.setLevel(level)

    if not any(isinstance(h, ElasticsearchLogHandler) for h in logger.handlers):
        es_handler = log_service.get_handler()
        es_handler.setLevel(level)
        formatter = logging.Formatter("%(asctime)s %(levelname)s %(name)s %(message)s")
        es_handler.setFormatter(formatter)
        logger.addHandler(es_handler)

    if not any(isinstance(h, logging.StreamHandler) and not isinstance(h, ElasticsearchLogHandler) for h in logger.handlers):
        stream_handler = logging.StreamHandler(sys.stdout)
        stream_handler.setLevel(level)
        stream_handler.setFormatter(logging.Formatter("%(asctime)s %(levelname)s %(name)s %(message)s"))
        logger.addHandler(stream_handler)

    logger.propagate = False
    return logger


def bootstrap() -> Dict[str, Any]:
    es_client = ElasticsearchClient()
    if not es_client.ping():
        raise ConnectionError(f"Unable to connect to Elasticsearch at {DEFAULT_ES_URL}")

    search_service = SearchService(es_client)
    log_service = LogService(es_client)

    search_setup = search_service.setup()
    log_setup = log_service.setup()

    return {
        "search_index": search_setup,
        "log_index": log_setup,
    }


