    time.sleep(1)

    search_results = search_service.query("Elasticsearch logging", filters={"category": "documentation"}, size=5)
    print(json.dumps(search_results, indent=2, default=str))

    logs_results = log_service.search_logs(query_text="exception OR issue", size=10)
    print(json.dumps(logs_results, indent=2, default=str))

    agg_results = log_service.aggregate(
        start_time=(datetime.now(timezone.utc).replace(minute=0, second=0, microsecond=0)).isoformat(),
        end_time=utc_now_iso(),
        interval="10m",
    )
    print(json.dumps(agg_results, indent=2, default=str))


